const aiResp = $input.first().json;
const form = $('🔧 Parse Brief1').first().json;
let character = {};
try {
  const raw = aiResp?.message?.content || '{}';
  character = JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  character = {
    bio: `${form.niche} creator from ${form.location}`,
    backstory: `${form.name} is a ${form.age}-year-old ${form.niche.toLowerCase()} enthusiast from ${form.location}.`,
    personality_traits: ['authentic', 'motivating', 'creative', 'relatable', 'energetic'],
    content_pillars: ['Tips', 'Day in Life', 'Inspiration', 'Behind the Scenes'],
    caption_style: 'Casual, warm, 1-2 emojis, ends with a question.',
    signature_elements: 'Consistent hairstyle, signature color, always smiling',
    target_audience: `18-30 year olds interested in ${form.niche.toLowerCase()}`,
    master_prompt: `A photorealistic portrait of ${form.physicalDesc}. ${form.aesthetic}. Shot on Canon EOS R5, 85mm lens, shallow depth of field, Instagram lifestyle photography.`,
    hashtag_bank: ['#ai', '#influencer', '#content', '#lifestyle', '#trending']
  };
}
return [{ json: { ...form, character } }];

const aiResp = $input.first().json;
const prev = $('\ud83d\udd00 Parse Character').first().json;
let days1to15 = [];
try {
  const raw = aiResp?.message?.content || '[]';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  days1to15 = Array.isArray(parsed) ? parsed : (parsed.calendar || parsed.days || []);
} catch (e) {
  days1to15 = [];
}
return [{ json: { ...prev, days1to15 } }];

const aiResp = $input.first().json;
const prev = $('\ud83d\udd00 Parse Days 1-15').first().json;
let days16to30 = [];
try {
  const raw = aiResp?.message?.content || '[]';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  days16to30 = Array.isArray(parsed) ? parsed : (parsed.calendar || parsed.days || []);
} catch (e) {
  days16to30 = [];
}
const fullCalendar = [...(prev.days1to15 || []), ...days16to30];
return [{ json: { ...prev, days1to15: undefined, calendar: fullCalendar } }];

// Split calendar into individual items for Google Sheets — one row per day
const d = $input.first().json;
const cal = d.calendar || [];

if (cal.length === 0) {
  return [{ json: { ...d, calendarRows: [] } }];
}

const rows = cal.map(day => ({
  day: day.day || '',
  type: day.type || '',
  photo_description: day.photo_description || '',
  ideogram_prompt: day.ideogram_prompt || '',
  caption: day.caption || '',
  hashtags: day.hashtags || '',
  posting_time: day.posting_time || '',
  status: 'Not Generated'
}));

return [{ json: { ...d, calendarRows: rows } }];

// Return each calendar day as a separate item for batch append to Calendar tab
const d = $input.first().json;
const rows = d.calendarRows || [];
const name = d.name;
const handle = d.handle;

if (rows.length === 0) return [];

return rows.map(row => ({ json: {
  Influencer: `${name} (${handle})`,
  'Day': row.day,
  'Type': row.type,
  'Photo Description': row.photo_description,
  'Ideogram Prompt': row.ideogram_prompt,
  'Caption': row.caption,
  'Hashtags': row.hashtags,
  'Posting Time': row.posting_time,
  'Image Status': 'Not Generated',
  'Video Status': 'Not Generated',
  'Posted': 'No'
} }));

const f = $input.first().json;
const name = (f['Influencer Name'] || '').trim();
const handle = (f['Instagram Handle'] || '').trim();
const niche = (f['Niche'] || '').trim();
const gender = (f['Gender'] || '').trim();
const age = (f['Age'] || '').trim();
const location = (f['Location'] || '').trim();
const personality = (f['Personality Vibe'] || '').trim();
const aesthetic = (f['Visual Aesthetic'] || '').trim();
const physical = (f['Specific Physical Description'] || '').trim();
const email = (f['Your Email'] || '').trim();
const physicalDesc = physical || `A ${age}-year-old ${gender.toLowerCase()} from ${location} with an attractive, photogenic appearance suitable for a ${niche.toLowerCase()} influencer.`;

return [{ json: { name, handle, niche, gender, age, location, personality, aesthetic, physicalDesc, email, timestamp: new Date().toISOString() }}];

const aiResp = $input.first().json;
const prev = $('\ud83d\udd00 Merge Full Calendar').first().json;
let extras = {};
try {
  const raw = aiResp?.message?.content || '{}';
  extras = JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  extras = { carousels: [], brand_pitches: [] };
}
return [{ json: { ...prev, carousels: extras.carousels || [], brandPitches: extras.brand_pitches || [] } }];

// Compile beautiful email with everything
const d = $('📊 Prepare Calendar Rows').first().json;
const c = d.character;
const cal = d.calendar || [];
const carousels = d.carousels || [];
const pitches = d.brandPitches || [];

let calText = '';
cal.forEach(day => {
  calText += `
--- DAY ${day.day} (${day.type}) ---
Photo: ${day.photo_description}

IDEOGRAM PROMPT (copy-paste this):
${day.ideogram_prompt}

CAPTION:
${day.caption}

HASHTAGS: ${day.hashtags}
BEST TIME: ${day.posting_time}
`;
});

let carText = '';
carousels.forEach((car, i) => {
  carText += `
=== CAROUSEL ${i+1}: ${car.title} ===
`;
  (car.slides || []).forEach(s => { carText += `Slide ${s.slide_num}: ${s.headline}
  ${s.body}
`; });
});

let pitchText = '';
pitches.forEach((p, i) => {
  pitchText += `
=== PITCH ${i+1}: ${p.brand_type} ===
Subject: ${p.subject}

${p.body}
`;
});

const megaEmail = `🤖 YOUR AI INFLUENCER IS READY: ${d.name} (${d.handle})

${'='.repeat(50)}
CHARACTER SHEET
${'='.repeat(50)}
Bio: ${c.bio}
Backstory: ${c.backstory}
Personality: ${(c.personality_traits||[]).join(', ')}
Content Pillars: ${(c.content_pillars||[]).join(', ')}
Caption Style: ${c.caption_style}
Signature Elements: ${c.signature_elements}
Target Audience: ${c.target_audience}

MASTER IDEOGRAM PROMPT:
${c.master_prompt}

HASHTAG BANK:
${(c.hashtag_bank||[]).join(' ')}

${'='.repeat(50)}
30-DAY CALENDAR (${cal.length} days generated)
${'='.repeat(50)}
${calText}

${'='.repeat(50)}
CAROUSEL SCRIPTS
${'='.repeat(50)}
${carText}

${'='.repeat(50)}
BRAND PITCH EMAILS
${'='.repeat(50)}
${pitchText}

${'='.repeat(50)}
NEXT STEPS
${'='.repeat(50)}
1. Open your Google Sheet — Calendar tab has 1 row per day
2. For Day 1: copy the Ideogram Prompt from the sheet
3. Open ideogram.ai → paste prompt → generate → download image
4. Upload image to kling.ai → generate 5-sec video clip
5. Open Canva for carousels, CapCut for reels
6. Post to Instagram with the caption and hashtags from the sheet
7. Update Image Status and Video Status columns as you go

Total cost: INR 0. Your AI influencer is ready to go live.`;

return [{ json: { ...d, megaEmail } }];

const input = $input.first().json;
const today = new Date();
const festivals = [
  {name:'Republic Day',month:1,day:26,themes:'patriotic outfits, tricolor themes'},
  {name:'Holi',month:3,day:14,themes:'vibrant colors, gulaal, festive energy'},
  {name:'Independence Day',month:8,day:15,themes:'patriotic fitness, tricolor outfits'},
  {name:'Ganesh Chaturthi',month:9,day:7,themes:'Ganpati celebrations, festive fitness'},
  {name:'Navratri',month:10,day:3,themes:'garba dance workouts, dandiya fitness'},
  {name:'Dussehra',month:10,day:12,themes:'victory, triumph, warrior poses'},
  {name:'Diwali',month:11,day:1,themes:'festival of lights, diyas, warm golden lighting'},
  {name:'Christmas',month:12,day:25,themes:'winter fitness, cozy workouts'},
  {name:'Pongal',month:1,day:14,themes:'harvest festival, sunrise workouts'},
  {name:'Eid ul-Fitr',month:3,day:31,themes:'celebration, community, togetherness'},
  {name:'Yoga Day',month:6,day:21,themes:'yoga poses, mindfulness, wellness'},
  {name:'Raksha Bandhan',month:8,day:19,themes:'sibling bonds, family fitness'}
];
const upcoming = [];
for (const f of festivals) {
  for (let y = 0; y <= 1; y++) {
    const d = new Date(today.getFullYear()+y, f.month-1, f.day);
    const diff = Math.floor((d-today)/(86400000));
    if (diff >= 0 && diff <= 30) upcoming.push({name:f.name,dayNumber:diff+1,themes:f.themes});
  }
}
const nicheTrends = {
  'Fitness & Wellness':['#FitIndia','#YogaWithMe','#HomeWorkout','#DesiGains'],
  'Fashion & Lifestyle':['#IndianFashion','#DesiStyle','#EthnicWear','#SustainableFashion'],
  'Beauty & Skincare':['#IndianBeauty','#DesiGlow','#AyurvedicBeauty','#CleanBeauty'],
  'Food & Cooking':['#IndianFood','#HealthyDesi','#DesiRecipes','#FoodieLife'],
  'Travel & Adventure':['#IncredibleIndia','#HiddenGems','#SoloTravel','#WeekendGetaway'],
  'Tech & Productivity':['#TechIndia','#StartupLife','#AIIndia','#DigitalIndia'],
  'Motivation & Mindset':['#MindfulLiving','#WellnessJourney','#SelfCare','#PositiveVibes'],
  'Finance & Business':['#FinanceIndia','#StartupLife','#MoneyTips','#InvestSmart']
};
const niche = input.niche || 'Fitness & Wellness';
const trends = nicheTrends[niche] || nicheTrends['Fitness & Wellness'];
let ctx = '';
if (upcoming.length > 0) {
  ctx += '\nFESTIVAL AWARENESS:\n';
  for (const u of upcoming) ctx += '- Day ' + u.dayNumber + ' near ' + u.name + ': ' + u.themes + '\n';
}
ctx += '\nTRENDING: ' + trends.join(', ') + '\nIncorporate 2-3 trending elements naturally.';
return [{json:{...input,trendContext:ctx,festivalsDetected:upcoming.length,upcomingFestivals:upcoming}}];

